#[tokio::test]
async fn test_loaned_auto_return() {
    let pool = Pool::new_simple(2, || vec![0u8; 100]);

    assert_eq!(pool.available(), 2);

    {
        let _item1 = pool.acquire().await;
        let _item2 = pool.acquire().await;
        assert_eq!(pool.available(), 0);
    } // Both items dropped here

    assert_eq!(pool.available(), 2); // Slots returned
}
```

