#[tokio::test]
async fn test_pool_throughput() {
    use std::time::Instant;

    let pool = Pool::new_simple(32, || vec![0u8; 8_000_000]);
    let iterations = 1000;

    let start = Instant::now();
    for _ in 0..iterations {
        let item = pool.acquire().await;
        drop(item);
    }
    let elapsed = start.elapsed();

    let ops_per_sec = iterations as f64 / elapsed.as_secs_f64();
    println!("Pool acquire/release: {:.0} ops/sec", ops_per_sec);

    // Should be >> 10000 ops/sec
    assert!(ops_per_sec > 10_000.0);
}
