# Create FrameData Type

**Purpose**: Define the poolable frame data structure that will replace per-frame Vec allocation.

## File to Create

```
crates/daq-driver-pvcam/src/components/frame_pool.rs
```

## FrameData Implementation

```rust
//! Frame pool types for zero-allocation frame handling.

use daq_pool::{Pool, Loaned};
use std::sync::Arc;

/// Raw frame data with metadata, suitable for pooling.
/// 
/// The buffer is pre-allocated and reused across frames.
/// Only metadata fields are reset between uses.
/// 
/// # Design Notes
/// 
/// - \`data\`: Pre-allocated to max frame size, never reallocated
/// - \`actual_len\`: Tracks actual bytes written (may be < capacity)
/// - Using \`actual_len\` instead of Vec::truncate() avoids reallocation
///   when frame sizes vary between acquisitions
#[derive(Debug)]
pub struct FrameData {
    /// Pre-allocated pixel buffer (capacity >= max frame size)
    pub data: Vec<u8>,

    /// Actual bytes written to data (may be < data.capacity())
    pub actual_len: usize,

    /// Frame width in pixels
    pub width: u32,

    /// Frame height in pixels  
    pub height: u32,

    /// Bits per pixel (typically 16 for scientific cameras)
    pub bit_depth: u32,

    /// Sequential frame number from camera hardware
    pub frame_number: u64,

    /// Timestamp in nanoseconds (from camera or system)
    pub timestamp_ns: u64,

    /// Exposure time if known
    pub exposure_ms: Option<f64>,

    /// ROI X offset (0 if full frame)
    pub roi_x: u32,

    /// ROI Y offset (0 if full frame)
    pub roi_y: u32,

    /// Optional timestamp at start of exposure (PVCAM-specific)
    pub timestamp_bof_ns: Option<u64>,

    /// Optional timestamp at end of exposure (PVCAM-specific)
    pub timestamp_eof_ns: Option<u64>,
}

impl FrameData {
    /// Create new FrameData with pre-allocated buffer.
    /// 
    /// # Arguments
    /// * \`capacity\` - Buffer size in bytes (should match max frame size)
    pub fn new(capacity: usize) -> Self {
        Self {
            data: vec![0u8; capacity],
            actual_len: 0,
            width: 0,
            height: 0,
            bit_depth: 16,
            frame_number: 0,
            timestamp_ns: 0,
            exposure_ms: None,
            roi_x: 0,
            roi_y: 0,
            timestamp_bof_ns: None,
            timestamp_eof_ns: None,
        }
    }

    /// Reset metadata for pool reuse.
    /// 
    /// The pixel buffer remains allocated - this is intentional!
    /// Only metadata is cleared to prepare for the next frame.
    pub fn reset(&mut self) {
        self.actual_len = 0;
        self.width = 0;
        self.height = 0;
        self.frame_number = 0;
        self.timestamp_ns = 0;
        self.exposure_ms = None;
        self.roi_x = 0;
        self.roi_y = 0;
        self.timestamp_bof_ns = None;
        self.timestamp_eof_ns = None;
        // Note: data buffer is NOT cleared - just rewritten on next use
    }

    /// Get actual pixel data slice (not full buffer capacity).
    #[inline]
    pub fn pixels(&self) -> &[u8] {
        &self.data[..self.actual_len]
    }

    /// Get mutable pixel data slice.
    #[inline]
    pub fn pixels_mut(&mut self) -> &mut [u8] {
        &mut self.data[..self.actual_len]
    }

    /// Get pixel data as u16 slice (for 16-bit cameras).
    /// 
    /// # Safety
    /// Assumes data is properly aligned and actual_len is even.
    pub fn pixels_u16(&self) -> &[u16] {
        assert!(self.actual_len % 2 == 0, "actual_len must be even for u16 slice");
        // SAFETY: Vec<u8> from vec![] is properly aligned, actual_len is even
        unsafe {
            std::slice::from_raw_parts(
                self.data.as_ptr() as *const u16,
                self.actual_len / 2,
            )
        }
    }

    /// Buffer capacity (maximum frame size this can hold).
    #[inline]
    pub fn capacity(&self) -> usize {
        self.data.capacity()
    }
}

impl Default for FrameData {
    fn default() -> Self {
        Self::new(0)
    }
}
```

