impl AcquisitionState {
    /// Initialize frame pool for streaming.
    /// 
    /// # Arguments
    /// * \`frame_bytes\` - Size of each frame in bytes
    /// * \`circular_buffer_count\` - PVCAM circular buffer size
    pub async fn initialize_frame_pool(
        &self,
        frame_bytes: usize,
        circular_buffer_count: usize,
    ) {
        let pool_size = circular_buffer_count * 2; // 2x headroom
        let pool = create_frame_pool(pool_size, frame_bytes);

        tracing::info!(
            target: "pvcam_pool",
            pool_size,
            frame_bytes,
            total_memory_mb = (pool_size * frame_bytes) / (1024 * 1024),
            "Frame pool initialized"
        );

        *self.frame_pool.lock().await = Some(pool);
    }

    /// Clear frame pool when streaming stops.
    pub async fn clear_frame_pool(&self) {
        let mut guard = self.frame_pool.lock().await;
        if let Some(pool) = guard.take() {
            tracing::info!(
                target: "pvcam_pool",
                final_size = pool.size(),
                initial_size = pool.initial_size(),
                "Frame pool cleared"
            );
        }
    }

    /// Get frame pool reference for frame loop.
    pub async fn get_frame_pool(&self) -> Option<Arc<FramePool>> {
        self.frame_pool.lock().await.clone()
    }
}
