//! Tap system for secondary frame consumers.
//!
//! Taps receive copies or references to frames, enabling multiple
//! consumers without preventing pool slot reclamation.

use crate::frame_pool::FrameData;
use tokio::sync::mpsc;

/// Handle returned when registering a tap.
/// Used for unregistration.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub struct TapHandle {
    pub(crate) id: u64,
}

/// Metadata snapshot (no pixel data).
#[derive(Debug, Clone)]
pub struct FrameMetadataSnapshot {
    pub frame_number: u64,
    pub timestamp_ns: u64,
    pub width: u32,
    pub height: u32,
    pub bit_depth: u32,
    pub exposure_ms: Option<f64>,
}

impl From<&FrameData> for FrameMetadataSnapshot {
    fn from(frame: &FrameData) -> Self {
        Self {
            frame_number: frame.frame_number,
            timestamp_ns: frame.timestamp_ns,
            width: frame.width,
            height: frame.height,
            bit_depth: frame.bit_depth,
            exposure_ms: frame.exposure_ms,
        }
    }
}

/// Tap consumer types for secondary frame access.
pub enum TapConsumer {
    /// Receives every Nth frame as Bytes.
    /// 
    /// Allocates a copy on the tap path only. Good for:
    /// - GUI preview (decimated display)
    /// - Network streaming (gRPC, WebSocket)
    /// 
    /// # Fields
    /// - \`sender\`: Channel to send frame bytes
    /// - \`nth\`: Decimation factor (1 = every frame, 10 = every 10th)
    Decimated {
        sender: mpsc::Sender<bytes::Bytes>,
        nth: usize,
    },

    /// Receives reference callback for each frame.
    /// 
    /// No allocation, but blocks frame loop during callback.
    /// Good for:
    /// - Statistics calculation
    /// - Lightweight logging
    /// - Fast validation
    /// 
    /// # Warning
    /// Callback runs in frame acquisition task - keep it FAST!
    Reference {
        callback: Box<dyn Fn(&FrameData) + Send + Sync>,
    },

    /// Receives metadata only (no pixel data).
    /// 
    /// Minimal allocation. Good for:
    /// - Frame counting
    /// - Timing analysis
    /// - Progress reporting
    MetadataOnly {
        sender: mpsc::Sender<FrameMetadataSnapshot>,
    },

    /// Receives every Nth frame as Bytes with metadata.
    /// 
    /// Like Decimated but includes frame metadata.
    DecimatedWithMetadata {
        sender: mpsc::Sender<(bytes::Bytes, FrameMetadataSnapshot)>,
        nth: usize,
    },
}

impl std::fmt::Debug for TapConsumer {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::Decimated { nth, .. } => {
                f.debug_struct("Decimated").field("nth", nth).finish()
            }
            Self::Reference { .. } => {
                f.debug_struct("Reference").finish()
            }
            Self::MetadataOnly { .. } => {
                f.debug_struct("MetadataOnly").finish()
            }
            Self::DecimatedWithMetadata { nth, .. } => {
                f.debug_struct("DecimatedWithMetadata").field("nth", nth).finish()
            }
        }
    }
}
```

