**Purpose**: Create the registry that manages tap consumers and dispatches frames.

## Add to tap.rs

```rust
use parking_lot::RwLock;
use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::Arc;

/// Registry managing tap consumers.
/// 
/// Thread-safe: can register/unregister taps while streaming.
pub struct TapRegistry {
    /// Registered taps with their IDs
    taps: RwLock<Vec<(u64, TapConsumer)>>,

    /// Next tap ID to assign
    next_id: AtomicU64,

    /// Total frames notified (for decimation)
    frame_counter: AtomicU64,
}

impl TapRegistry {
    /// Create empty registry.
    pub fn new() -> Self {
        Self {
            taps: RwLock::new(Vec::new()),
            next_id: AtomicU64::new(1),
            frame_counter: AtomicU64::new(0),
        }
    }

    /// Register a new tap consumer.
    /// 
    /// Returns handle for later unregistration.
    pub fn register(&self, consumer: TapConsumer) -> TapHandle {
        let id = self.next_id.fetch_add(1, Ordering::Relaxed);

        tracing::debug!(
            target: "pvcam_tap",
            tap_id = id,
            tap_type = ?consumer,
            "Tap registered"
        );

        self.taps.write().push((id, consumer));
        TapHandle { id }
    }

    /// Unregister a tap by handle.
    pub fn unregister(&self, handle: TapHandle) {
        let mut taps = self.taps.write();
        let prev_len = taps.len();
        taps.retain(|(id, _)| *id != handle.id);

        if taps.len() < prev_len {
            tracing::debug!(
                target: "pvcam_tap",
                tap_id = handle.id,
                "Tap unregistered"
            );
        }
    }

    /// Notify all taps of a new frame.
    /// 
    /// Called from frame acquisition loop BEFORE sending to primary.
    /// 
    /// # Performance Notes
    /// - Reference taps block this call
    /// - Decimated/Metadata taps use try_send (non-blocking)
    pub fn notify(&self, frame: &FrameData) {
        let count = self.frame_counter.fetch_add(1, Ordering::Relaxed);
        let taps = self.taps.read();

        for (id, tap) in taps.iter() {
            match tap {
                TapConsumer::Decimated { sender, nth } => {
                    if count % (*nth as u64) == 0 {
                        // Copy frame data for tap
                        let bytes = bytes::Bytes::copy_from_slice(frame.pixels());
                        if sender.try_send(bytes).is_err() {
                            tracing::trace!(
                                target: "pvcam_tap",
                                tap_id = id,
                                "Decimated tap channel full, dropping"
                            );
                        }
                    }
                }

                TapConsumer::Reference { callback } => {
                    // Direct callback - blocks frame loop!
                    callback(frame);
                }

                TapConsumer::MetadataOnly { sender } => {
                    let snapshot = FrameMetadataSnapshot::from(frame);
                    if sender.try_send(snapshot).is_err() {
                        tracing::trace!(
                            target: "pvcam_tap",
                            tap_id = id,
                            "Metadata tap channel full, dropping"
                        );
                    }
                }

                TapConsumer::DecimatedWithMetadata { sender, nth } => {
                    if count % (*nth as u64) == 0 {
                        let bytes = bytes::Bytes::copy_from_slice(frame.pixels());
                        let snapshot = FrameMetadataSnapshot::from(frame);
                        if sender.try_send((bytes, snapshot)).is_err() {
                            tracing::trace!(
                                target: "pvcam_tap",
                                tap_id = id,
                                "DecimatedWithMetadata tap channel full, dropping"
                            );
                        }
                    }
                }
            }
        }
    }

    /// Get current frame count.
    pub fn frame_count(&self) -> u64 {
        self.frame_counter.load(Ordering::Relaxed)
    }

    /// Get number of registered taps.
    pub fn tap_count(&self) -> usize {
        self.taps.read().len()
    }

    /// Reset frame counter (for new acquisition).
    pub fn reset_counter(&self) {
        self.frame_counter.store(0, Ordering::Relaxed);
    }
}

impl Default for TapRegistry {
    fn default() -> Self {
        Self::new()
    }
}
```

