#[cfg(test)]
mod tests {
    use super::*;
    use tokio::sync::mpsc;

    fn test_frame() -> FrameData {
        let mut frame = FrameData::new(100);
        frame.actual_len = 50;
        frame.frame_number = 1;
        frame.width = 10;
        frame.height = 5;
        for i in 0..50 {
            frame.data[i] = i as u8;
        }
        frame
    }

    #[test]
    fn test_register_unregister() {
        let registry = TapRegistry::new();

        let (tx, _rx) = mpsc::channel(10);
        let handle = registry.register(TapConsumer::MetadataOnly { sender: tx });

        assert_eq!(registry.tap_count(), 1);

        registry.unregister(handle);
        assert_eq!(registry.tap_count(), 0);
    }

    #[tokio::test]
    async fn test_decimated_tap() {
        let registry = TapRegistry::new();
        let (tx, mut rx) = mpsc::channel(10);

        registry.register(TapConsumer::Decimated {
            sender: tx,
            nth: 2,  // Every 2nd frame
        });

        let frame = test_frame();

        // Frame 0: should receive (0 % 2 == 0)
        registry.notify(&frame);
        assert!(rx.try_recv().is_ok());

        // Frame 1: should NOT receive (1 % 2 != 0)
        registry.notify(&frame);
        assert!(rx.try_recv().is_err());

        // Frame 2: should receive (2 % 2 == 0)
        registry.notify(&frame);
        assert!(rx.try_recv().is_ok());
    }

    #[test]
    fn test_reference_tap() {
        use std::sync::atomic::AtomicU32;

        let registry = TapRegistry::new();
        let counter = Arc::new(AtomicU32::new(0));
        let counter_clone = counter.clone();

        registry.register(TapConsumer::Reference {
            callback: Box::new(move |_frame| {
                counter_clone.fetch_add(1, Ordering::Relaxed);
            }),
        });

        let frame = test_frame();
        registry.notify(&frame);
        registry.notify(&frame);

        assert_eq!(counter.load(Ordering::Relaxed), 2);
    }
}
