## Update Frame Generation Loop

```rust
impl MockCamera {
    async fn frame_generation_loop(&self) {
        let pool = create_frame_pool(32, self.frame_size());
        let primary_tx = self.primary_tx.lock().await.clone();
        let tap_registry = self.tap_registry.clone();

        loop {
            if !self.is_streaming().await.unwrap_or(false) {
                break;
            }

            // Generate mock frame
            let mut frame = pool.acquire().await;
            self.populate_mock_frame(&mut frame);

            // Notify taps
            tap_registry.notify(&frame);

            // Send to primary
            if let Some(ref tx) = primary_tx {
                if tx.send(frame).await.is_err() {
                    break; // Consumer disconnected
                }
            }

            tokio::time::sleep(self.frame_interval()).await;
        }
    }

    fn populate_mock_frame(&self, frame: &mut FrameData) {
        // Fill with test pattern
        let (w, h) = self.resolution();
        frame.width = w;
        frame.height = h;
        frame.bit_depth = 16;
        frame.frame_number = self.frame_count.fetch_add(1, Ordering::Relaxed);
        frame.timestamp_ns = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap()
            .as_nanos() as u64;

        // Generate simple gradient pattern
        let bytes_per_pixel = 2;
        frame.actual_len = (w * h * bytes_per_pixel) as usize;
        for i in 0..frame.actual_len {
            frame.data[i] = (i % 256) as u8;
        }
    }
}
```

