## Current Pattern

```rust
// Current: Uses subscribe_frames broadcast
async fn stream_frames(
    &self,
    request: Request<StreamFramesRequest>,
) -> Result<Response<Self::StreamFramesStream>, Status> {
    let rx = device.subscribe_frames().await
        .ok_or_else(|| Status::unavailable("Streaming not supported"))?;

