## New Pattern

```rust
async fn stream_frames(
    &self,
    request: Request<StreamFramesRequest>,
) -> Result<Response<Self::StreamFramesStream>, Status> {
    let req = request.get_ref();
    let device = self.get_frame_producer(&req.device_id)
        .map_err(|e| Status::not_found(e.to_string()))?;

    // Parse request parameters
    let decimation = req.decimation.unwrap_or(1) as usize;
    let compress = req.compress.unwrap_or(false);

    // Create channel for this client
    let (tx, mut rx) = mpsc::channel(100);

    // Register tap
    let handle = device.register_tap(TapConsumer::Decimated {
        sender: tx,
        nth: decimation,
    }).await.map_err(|e| Status::internal(e.to_string()))?;

    // Create cleanup handle for when client disconnects
    let device_clone = device.clone();
    let cleanup_handle = handle;

    // Build stream
    let stream = async_stream::stream! {
        while let Some(bytes) = rx.recv().await {
            // Optionally compress
            let data = if compress {
                lz4_flex::compress_prepend_size(&bytes)
            } else {
                bytes.to_vec()
            };

            yield Ok(FrameResponse {
                data,
                frame_number: 0, // TODO: include metadata
                timestamp_ns: 0,
                width: 0,
                height: 0,
            });
        }

        // Cleanup when stream ends
        let _ = device_clone.unregister_tap(cleanup_handle).await;
    };

    Ok(Response::new(Box::pin(stream)))
}
```

## Handle Client Disconnection

```rust
// Ensure tap is unregistered when client disconnects
impl Drop for StreamHandle {
    fn drop(&mut self) {
        // Cannot easily unregister in drop (async)
        // Options:
        // 1. Use tokio::spawn for cleanup
        // 2. Track active taps and clean periodically
        // 3. Let tap sender disconnect naturally
    }
}

// Alternative: Use oneshot for cleanup signal
async fn stream_with_cleanup(/* ... */) {
    let (cleanup_tx, cleanup_rx) = tokio::sync::oneshot::channel();

    // Spawn cleanup task
    let device_clone = device.clone();
    let handle_clone = handle;
    tokio::spawn(async move {
        let _ = cleanup_rx.await; // Wait for signal
        let _ = device_clone.unregister_tap(handle_clone).await;
    });

    // Build stream
    let stream = async_stream::stream! {
        while let Some(bytes) = rx.recv().await {
            yield Ok(/* ... */);
        }
        // Signal cleanup
        let _ = cleanup_tx.send(());
    };
}
```

