## Test for Pool Behavior

```rust
#[tokio::test]
async fn test_pool_slot_return() {
    let driver = create_driver().await;

    let (tx, mut rx) = mpsc::channel(10);
    driver.register_primary_output(tx).await.unwrap();

    // Get initial pool size
    let initial_available = driver.pool_available().await;

    driver.start_stream().await.unwrap();

    // Receive and hold frames
    let frame1 = rx.recv().await.unwrap();
    let frame2 = rx.recv().await.unwrap();

    // Pool should have fewer available slots
    assert!(driver.pool_available().await < initial_available);

    // Drop frames
    drop(frame1);
    drop(frame2);

    // Wait for return
    tokio::time::sleep(Duration::from_millis(10)).await;

    // Slots should be returned
    assert_eq!(driver.pool_available().await, initial_available);

    driver.stop_stream().await.unwrap();
}
```

