            let data = vec![0u8; FRAME_SIZE];
            black_box(data)
        })
    });

    // OLD WAY: Vec + Arc allocation
    group.bench_function("vec_plus_arc", |b| {
        use std::sync::Arc;
        b.iter(|| {
            let data = vec![0u8; FRAME_SIZE];
            let arc = Arc::new(data);
            black_box(arc)
        })
    });

    // NEW WAY: Pool acquire/release
    group.bench_function("pool_acquire_release", |b| {
        let rt = tokio::runtime::Runtime::new().unwrap();
        let pool = rt.block_on(async {
            daq_pool::Pool::new_simple(32, || vec![0u8; FRAME_SIZE])
        });

        b.iter(|| {
            rt.block_on(async {
                let item = pool.acquire().await;
                black_box(item)
                // Dropped here, returns to pool
            })
        })
    });

    // NEW WAY: Pool with simulated copy
    group.bench_function("pool_with_copy", |b| {
        let rt = tokio::runtime::Runtime::new().unwrap();
        let pool = rt.block_on(async {
            daq_pool::Pool::new_simple(32, || vec![0u8; FRAME_SIZE])
        });
        let src_data = vec![0xABu8; FRAME_SIZE];

        b.iter(|| {
            rt.block_on(async {
                let mut item = pool.acquire().await;
                // Simulate memcpy from SDK buffer
                unsafe {
                    std::ptr::copy_nonoverlapping(
                        src_data.as_ptr(),
                        item.as_mut_ptr(),
                        FRAME_SIZE
                    );
                }
                black_box(item)
            })
        })
    });

    group.finish();
}

fn bench_throughput(c: &mut Criterion) {
    let mut group = c.benchmark_group("frame_throughput");

    // Measure frames per second with each approach

    group.bench_function("vec_100_frames", |b| {
        b.iter(|| {
            for _ in 0..100 {
                let data = vec![0u8; FRAME_SIZE];
                black_box(&data);
            }
        })
    });

    group.bench_function("pool_100_frames", |b| {
        let rt = tokio::runtime::Runtime::new().unwrap();
        let pool = rt.block_on(async {
            daq_pool::Pool::new_simple(32, || vec![0u8; FRAME_SIZE])
        });

        b.iter(|| {
            rt.block_on(async {
                for _ in 0..100 {
                    let item = pool.acquire().await;
                    black_box(&*item);
                }
            })
        })
