#[tokio::test]
async fn profile_concurrent_lock_contention() {
    use std::sync::Arc;
    use tokio::sync::Barrier;

    let pool = create_frame_pool(32, 8_000_000);
    let barrier = Arc::new(Barrier::new(8));

    let handles: Vec<_> = (0..8).map(|_| {
        let pool = pool.clone();
        let barrier = barrier.clone();

        tokio::spawn(async move {
            barrier.wait().await;

            let mut max_lock_time = Duration::ZERO;
            for _ in 0..1000 {
                let frame = pool.acquire().await;
                let start = std::time::Instant::now();
                let _ = frame.get();
                max_lock_time = max_lock_time.max(start.elapsed());
            }
            max_lock_time
        })
    }).collect();

    let results = futures::future::join_all(handles).await;
    let max_across_threads = results.iter()
        .filter_map(|r| r.as_ref().ok())
        .max()
        .unwrap();

    println!("Max lock time across 8 threads: {:?}", max_across_threads);

    // Should be < 1ms even under contention
    assert!(*max_across_threads < Duration::from_millis(1));
}
