#[tokio::test]
#[ignore]  // Run manually: cargo test pool_stress -- --ignored
async fn test_pool_under_sustained_backpressure() {
    let driver = MockPvcamDriver::new();
    driver.set_pool_size(10);
    driver.set_frame_rate(100.0);  // 100 FPS

    let mut rx = driver.register_primary_output().await.unwrap();
    driver.start_stream().await.unwrap();

    // Simulate slow consumer: process 1 frame per 20ms (50 FPS throughput)
    let start = Instant::now();
    while start.elapsed() < Duration::from_secs(5) {
        if let Some(frame) = rx.recv().await {
            tokio::time::sleep(Duration::from_millis(20)).await;
            drop(frame);
        }
    }

    let metrics = driver.pool_metrics();
    // Expect ~50% frame drop rate
    let total = metrics.frames_acquired.load(Ordering::Relaxed);
    let dropped = metrics.frames_dropped_pool_exhaustion.load(Ordering::Relaxed);
    let drop_rate = dropped as f64 / total as f64;

    assert!(drop_rate > 0.4 && drop_rate < 0.6, 
        "Expected ~50% drop rate, got {:.1}%", drop_rate * 100.0);
}
