// src/builder.rs (new file)
use daq_hardware::driver_builder::{DriverBuilder, DeviceComponents};
use futures::future::BoxFuture;
use serde::Deserialize;
use std::sync::Arc;

#[derive(Deserialize)]
struct PvcamConfig {
    camera_name: String,
    #[serde(default)]
    exposure_ms: Option<f64>,
}

pub struct PvcamBuilder;

impl DriverBuilder for PvcamBuilder {
    fn name(&self) -> &'static str { "pvcam" }

    fn description(&self) -> &'static str {
        "Teledyne Photometrics PVCAM camera"
    }

    fn capabilities(&self) -> &'static [&'static str] {
        &["FrameProducer", "ExposureControl", "Triggerable", "Parameterized"]
    }

    fn validate(&self, config: &toml::Value) -> anyhow::Result<()> {
        PvcamConfig::deserialize(config.clone())?;
        Ok(())
    }

    fn build(&self, config: toml::Value) -> BoxFuture<'static, anyhow::Result<DeviceComponents>> {
        Box::pin(async move {
            let cfg: PvcamConfig = config.try_into()?;

            // Use existing camera initialization
            let camera = PvcamCamera::open(&cfg.camera_name).await?;

            if let Some(exposure) = cfg.exposure_ms {
                camera.set_exposure(exposure).await?;
            }

            let driver = Arc::new(camera);

            Ok(DeviceComponents::new()
                .with_frame_producer(driver.clone())
                .with_exposure_control(driver.clone())
                .with_triggerable(driver.clone())
                .with_parameterized(driver))
        })
    }
}

inventory::submit!(&PvcamBuilder as &dyn DriverBuilder);
```

