use std::env;
use std::fs;
use daq_scripting::{RhaiEngine, traits::ScriptEngine};

#[tokio::main]
async fn main() {
    let args: Vec<String> = env::args().collect();
    let script_path = args.get(1).expect("Usage: rhai-runner <script.rhai>");
    let max_ops = args.get(2).and_then(|s| s.parse().ok()).unwrap_or(1_000_000);

    let script = fs::read_to_string(script_path).expect("Failed to read script");
    let mut engine = RhaiEngine::with_hardware_and_limit(max_ops).unwrap();

    match engine.execute_script(&script).await {
        Ok(r) => println!("Success: {:?}", r),
        Err(e) => { eprintln!("Error: {:?}", e); std::process::exit(1); }
    }
}
```

