fn read_snapshot(&self) -> Option<RingBufferSnapshot> {
    #[cfg(debug_assertions)]
    if tokio::runtime::Handle::try_current().is_ok() {
        tracing::warn!(
            target: "daq_storage::ring_buffer",
            "Blocking RingBuffer::read_snapshot called from async context! \
             Use AsyncRingBuffer::read_snapshot() instead to avoid stalling the runtime."
        );
    }

