    /// Wrapped driver instance (Arc for Rhai cloning)
    pub driver: Arc<GenericSerialDriver>,
    /// Soft position limits (validated before hardware commands)
    pub soft_limits: SoftLimits,
    /// Device identifier for logging/measurements
    pub device_id: String,
}
