## Implementation
```rust
engine.register_fn(
    "create_generic_driver",
    |config_path: &str, port_path: &str, address: &str| -> Result<GenericDriverHandle, Box<EvalAltResult>> {
        let config_path = std::path::PathBuf::from(config_path);
        let port_path = port_path.to_string();
        let address = address.to_string();

        run_blocking("create_generic_driver", async move {
            // 1. Load config FIRST (need baud_rate)
            let config = load_device_config(&config_path)
                .context("Failed to load device config")?;

            let baud_rate = config.connection.baud_rate;
            let device_name = config.device.name.clone();

            // 2. Open port with correct baud rate
            let port = open_serial_async(&port_path, baud_rate, &device_name)
                .await
                .context("Failed to open serial port")?;

            // 3. Wrap in GenericSerialDriver's SharedPort type (CRITICAL: unbuffered!)
            let shared: SharedPort = Arc::new(Mutex::new(Box::new(port)));

            // 4. Create driver
            let driver = GenericSerialDriver::new(config, shared, &address)
                .context("Failed to create driver")?;

            Ok(GenericDriverHandle {
                driver: Arc::new(driver),
                soft_limits: SoftLimits::unlimited(),
                device_id: format!("generic_{}", address),
            })
        })
    },
);
```

