```rust
engine.register_fn("format_command", |handle: &mut GenericDriverHandle, cmd_name: &str, params: rhai::Map| -> Result<String, Box<EvalAltResult>> {
    let cmd_name = cmd_name.to_string();

    // Convert Rhai Map to HashMap<String, f64>
    let params_f64: std::collections::HashMap<String, f64> = params
        .iter()
        .filter_map(|(k, v)| {
            v.as_float().ok().or_else(|| v.as_int().ok().map(|i| i as f64))
                .map(|f| (k.to_string(), f))
        })
        .collect();

    run_blocking("GenericDriver format_command", async move {
        handle.driver.format_command(&cmd_name, &params_f64).await
    })
});
```

