## Function Signature
```rust
/// Register all GenericDriver bindings with the Rhai engine.
///
/// This function registers:
/// - `GenericDriver` type
/// - Factory: `create_generic_driver(config_path, port_path, address)`
/// - Movable: `move_abs`, `move_rel`, `position`, `wait_settled`, `stop`
/// - Readable: `read`
/// - WavelengthTunable: `set_wavelength`, `get_wavelength`
/// - ShutterControl: `open`, `close`, `is_open`
/// - Low-level: `transaction`, `send_command`, `format_command`
/// - Parameters: `get_param`, `set_param`, `address`
/// - Safety: `set_soft_limits`
///
/// # Example
/// ```rust,ignore
/// let mut engine = Engine::new();
/// register_generic_driver_bindings(&mut engine);
/// ```
pub fn register_generic_driver_bindings(engine: &mut Engine) {
    // Register type
    engine.register_type_with_name::<GenericDriverHandle>("GenericDriver");

    // Factory function
    engine.register_fn("create_generic_driver", ...);

    // Movable trait (5 methods)
    engine.register_fn("move_abs", ...);
    engine.register_fn("move_rel", ...);
    engine.register_fn("position", ...);
    engine.register_fn("wait_settled", ...);
    engine.register_fn("stop", ...);

    // Readable trait (1 method)
    engine.register_fn("read", ...);

    // WavelengthTunable trait (2 methods)
    engine.register_fn("set_wavelength", ...);
    engine.register_fn("get_wavelength", ...);

    // ShutterControl trait (3 methods)
    engine.register_fn("open", ...);
    engine.register_fn("close", ...);
    engine.register_fn("is_open", ...);

    // Low-level API (3 methods)
    engine.register_fn("transaction", ...);
    engine.register_fn("send_command", ...);
    engine.register_fn("format_command", ...);

    // Parameter access (4 methods)
    engine.register_fn("get_param", ...);
    engine.register_fn("set_param", ...);
    engine.register_fn("address", ...);
    engine.register_fn("set_soft_limits", ...);
}
```

