    async fn instantiate_dynamic(
        &self,
        driver_type: &str,
        config: toml::Value,
    ) -> Result<DeviceComponents> {
        // Find builder in inventory
        let builder = inventory::iter::<&dyn DriverBuilder>
            .into_iter()
