    iteration = iteration,
    heuristic_count = enrichment.heuristics.len(),
    playbook_count = enrichment.playbooks.len(),
    kg_available = enrichment.kg_available,
    query_time_ms = enrichment.query_time_ms,
    "KG enrichment complete"
